{"symbol":"Users-naman-Documents-QBApps-qbapi.app.PayPhiWorldLine.PayPhiWorldLine.refundOrder","qualified_name":"Users-naman-Documents-QBApps-qbapi.app.PayPhiWorldLine.PayPhiWorldLine.refundOrder","label":"Method","pagerank":0.00004495953137303061,"is_key_symbol":false,"definition":{"file_path":"app/PayPhiWorldLine.php","start_line":339,"end_line":427,"signature":"($dataArray, $chainID)","source":"    public static function refundOrder($dataArray, $chainID){
        try {
            $status = array();
            $headerInfo = array();
            $finalArray = array();
            $PayPhiTable = Constants::getGlobalTableName("payphiPaymentIntent");
            $urlKey = self::getUrlEnvWise();
            $uri = $urlKey . "/" .self::$REFUND_API;

            $minified = json_encode(json_decode($dataArray));
            $hash = self::hashCalculation($minified, env("SECRET_KEY_WORLDINE"));

            $invoiceData = convertToArray(DB::table($PayPhiTable)->where("chainID", $chainID)->where("storeID", $dataArray["storeID"])->where("invoiceNumber", $dataArray["invoiceNo"])->first());
            if(empty($invoiceData)){
                $status["status"] = false;
                $status["message"]= "Invoice not found for this storeID";
                return $status;
            }

            if(empty($invoiceData["paymentMode"])){
                $status["status"] = false;
                $status["message"]= "order not commplete, can not refund!";
                return $status;
            }

            $currentDate = date('Y-m-d');
            $invoice = new DateTime($invoiceData["paymentTimeLocal"]);
            $invoiceDatee = $invoice->format('Y-m-d');
            $dataArray['referenceNo'] = self::cleanString($dataArray["referenceNo"]);
            $transactionType = NULL;
            if(isset($invoiceData["paymentMode"]) && $invoiceData["paymentMode"] != NULL){
                $transactionType = "REFUND";
                if($invoiceData["paymentMode"] == "Card"){
                    $transactionType = "VOID";
                }
            }

            $finalArray["aggregatorId"]    = $dataArray["aggregatorId"];
            $finalArray["amount"]          = number_format($invoiceData["amount"], 2, '.', '');
            $finalArray["invoiceNo"]       = $dataArray["invoiceNo"];
            $finalArray["posAppId"]        = $dataArray["posAppId"];
            $finalArray["referenceNo"]     = $dataArray["referenceNo"];
            $finalArray["storeCode"]       = $invoiceData["storeCode"];
            $finalArray["transactionType"] = $transactionType;

            // pass without posTillNo to minified
            $minified = json_encode($finalArray, JSON_UNESCAPED_UNICODE|JSON_UNESCAPED_SLASHES);
            $hash = self::hashCalculation($minified, env("SECRET_KEY_WORLDINE"));

            $headerInfo = array(
                'secureHash: '.$hash,
                'Content-Type: application/json'
            );

            $finalArray["posTillNo"] = $dataArray["posTillNo"];

            $response = self::commonCurlFunction($finalArray, $chainID, $uri, $headerInfo);
            if(empty($response)){
                $status["status"] = false;
                $status["message"] = "something went wrong! didn't get response";
                return $status;
            }

            if(isset($response) && $response["responseCode"] == "0000"){
                $PayPhiUpdateArray = array();
                $PayPhiUpdateArray["invoiceNumber"]    = $response["invoiceNo"];
                $PayPhiUpdateArray["referenceNo"]      = $response["referenceNo"];
                $PayPhiUpdateArray["transactionType"]  = "REF";
                $PayPhiUpdateArray["gatewayPaymentID"] = $response["paymentId"];
                $PayPhiUpdateArray["gatewayOrderID"]   = $response["txnID"];
                date_default_timezone_set('Asia/Kolkata');
                $PayPhiUpdateArray["paymentTimeLocal"] = date("Y-m-d H:i:s");
                date_default_timezone_set('UTC');
                $PayPhiUpdateArray["paymentTimeUTC"]   = date("Y-m-d H:i:s");
                $isUpdated = DB::table($PayPhiTable)->where("chainID", $chainID)->where("orderID", $response["invoiceNo"])->update($PayPhiUpdateArray);

                $status["status"] = true;
                $status["data"]   = $response;
                return $status;
            }

            $status["status"] = false;
            $status["message"] = "failed";
            $status["message"] = $response;
            return $status;
        } catch (\Exception $e){
            echo $e->getMessage();
        }
