public function refundOrder(Request $request)
{
	$storeID = $request->segment(3);
	$result = $request->getContent();
	if (isJson($result) == false) {
		$rest = "Invalid Data";
		return response()->json($rest, 422, [], JSON_NUMERIC_CHECK);
	}
	$data = convertToArray(json_decode($result));

	//Standards::debugEmail($restId,62, 'nikhiljha0192@gmail.com','Void order JSON Tracker',$data);
	if (isset($data['refundStoreID']) && $data['refundStoreID'] > 0) {
		$storeID = $data['refundStoreID'];
	}
	$invoiceStoreID = $request->header('storeID');
	$voidDeviceID = $request->header('deviceid');
	$data['voidDeviceID'] = $voidDeviceID;
	$order = Order::updateOrder($storeID, $invoiceStoreID, $data);
	if ($order["orderUpdationReport"]["status"] === "Updated") {


		$listOfChainsTable = Constants::getGlobalTableName("listOfChains");
		$chainSettingsTable = Constants::getGlobalTableName("chainSettings");
		$chainID = $order["chainID"];
		$checkChain = convertToArray(DB::table("$listOfChainsTable AS A")->join("$chainSettingsTable AS B", "A.chainID", "=", "B.chainRefID")->where("A.chainID", $chainID)->select("enableAccounting", "industry", "industrySubType", 'enableNavisionIntegration', 'enableMobiquestIntegration', 'enableMysquareIntegration', 'enableIRDIntegration', 'enableZohoIntegration', 'enableUnicommerceIntegration', 'enableSalesTarget', 'enableStockLedger')->get());
		$industry = $checkChain[0]["industry"];
		$industrySubType = $checkChain[0]["industrySubType"];
		$enableNavisionIntegration = $checkChain[0]['enableNavisionIntegration'];
		$enableIRDIntegration = $checkChain[0]['enableIRDIntegration'];
		$enableZohoIntegration = $checkChain[0]['enableZohoIntegration'];
		$enableUnicommerceIntegration = $checkChain[0]['enableUnicommerceIntegration'];
		$enableMobiQuestIntegration = $checkChain[0]['enableMobiquestIntegration'];
		$enableEcomReservation = $checkChain[0]['enableEcomReservation'];
		$enableSalesTarget = $checkChain[0]['enableSalesTarget'];
		$enableStockLedger = $checkChain[0]['enableStockLedger'];

		$qData = $order["updateQuantity"];
		$qData["transType"] = "ORDER_RETURN";
		$qData["transactionID"] = $data["orderID"];
		$qData["updateProdBatchQuantity"] = $order["updateProdBatchQuantity"];
		$sourceID = $storeID;
		$orderID = $data["orderID"];
		$sourceType = "STORE";
		$orderSummary = $order["orderSummary"];
		$orderPayment = $order["orderPayment"];
		$chainID = $order["chainID"];
		$checkIfInventoryManaged = Standards::getIfChainInventoryManaged($chainID);
		$checkIfRestaurantManaged = Standards::getIfStoreInventoryManaged($storeID);
		$queueNumber = queueNumber($chainID);

		if ($checkIfRestaurantManaged != 0 && $checkIfInventoryManaged != 0 && $enableStockLedger == 0) {

			$mailArray = array();
			$mailArray['data'] = $qData;
			$mailArray['queueNumber'] = $queueNumber;
			//Mailer::mailResponse('nikhil@maplegraph.com', "Data Array Controller", json_encode($mailArray));
			$job = (new StockJob($sourceID, $sourceType, $qData))->onQueue("$queueNumber");
			$this->dispatch($job);

		} elseif ($checkIfRestaurantManaged != 0 && $checkIfInventoryManaged != 0 && $enableStockLedger == 1) {
			$ledgerArray = array();
			$ledgerArray['sourceID'] = $storeID;
			$ledgerArray['sourceType'] = 'STORE';
			$ledgerArray['inventorySourceID'] = $storeID;
			$ledgerArray['inventorySourceType'] = 'STORE';
			if ($request->header('storeID') && $request->header('storeID') > 0) {
				$ledgerArray['inventorySourceID'] = $request->header('storeID');
			}
			$ledgerArray['transactionID'] = $data['refundOrderID'];
			$ledgerArray['transactionDataSource'] = 'ORDER_REFUND';
			$ledgerArray['transactionType'] = 'SALES_RETURN';
			$job = (new StockLedgerJob($ledgerArray, $chainID))->onQueue("$queueNumber");
			$this->dispatch($job);

		}
		// dispatch Job for the Void order detail
		$queueNumberVoid = queueNumber($chainID);
		$jobVoid = (new VoidOrderJob($chainID, $orderID, $storeID))->onQueue("$queueNumberVoid");
		$this->dispatch($jobVoid);
		Log::info("void mail job", ["jobVoid" => $jobVoid, "chainID" => $chainID, "storeID" => $storeID, "storeID" => $storeID]);

		// dispatch job for void loyalty point

		$queueNumberVoidLoyalty = queueNumber($chainID);
		$jobVoidLoyaltyPoint = (new VoidLoyaltyPointJob($chainID, $storeID, $data))->onQueue("$queueNumberVoidLoyalty");
		$this->dispatch($jobVoidLoyaltyPoint);

		// dispatch jon for ecom payment refund

		if ($order['isOnlinOrder'] == true) {

			$queueNumberVoidEcomPayment = queueNumber($chainID);
			$ecomOrderRefundArray = $order['ecomOrderRefund'];
			$jobVoidEcomPayment = (new EcomVoidOrderPaymentRefundJob($ecomOrderRefundArray))->onQueue("$queueNumberVoidEcomPayment");
			$this->dispatch($jobVoidEcomPayment);

		}

		//     Log::info("void loyalty Point JOB",["jobVoidLoyaltyPoint" => $jobVoidLoyaltyPoint,"chainID" => $chainID,"storeID" => $storeID, "data" => $data]);

		// Log::info("void mail job",["jobVoid" => $jobVoid,"chainID" => $chainID,"storeID" => $storeID, "storeID" => $storeID]);

		$queueNumber1 = queueNumber($chainID);
		$globalQueue = queueNumber('global');
		$job1 = (new GlobalOrderJobUpdate($chainID, $orderSummary, $orderPayment))->onQueue("$globalQueue");
		$this->dispatch($job1);

		unset($orderSummary["paymentType"]);

		//enable sales target
		if ($enableSalesTarget) {
			$salesTargetArray = array();
			$salesTargetArray["orderID"] = $data["orderID"];
			$salesTargetArray["refundOrderID"] = $data["refundOrderID"];
			$salesTargetArray["storeID"] = $storeID;
			$salesTargetArray["chainID"] = $chainID;
			$salesTargetArray["type"] = "REFUND";
			$salesTargetJob = (new SalesTargetJob($salesTargetArray, $chainID))->onQueue($queueNumber)->delay(6);
			$this->dispatch($salesTargetJob);
			$order["targetJob"] = $salesTargetJob;

		}

		//enable unicommerce
		if ($enableUnicommerceIntegration == 1) {
			$orderID = $data["orderID"];
			$orderSummaryTable = Constants::getChainTableName($chainID, "orderSummary");
			$orderSummaryDetails = convertToArray(DB::table($orderSummaryTable)->select('PINumber')->where('orderID', $orderID)->first());
			if (!empty($orderSummaryDetails)) {

				$unicommerceArray = array();
				$unicommerceArray["storeID"] = $storeID;
				$unicommerceArray["orderID"] = $orderID;
				$unicommerceArray["proformaInvoiceID"] = $orderSummaryDetails['PINumber'];
				$unicommerceArray["refundOrderID"] = $data['refundOrderID'];
				$queueNumberCancelSaleOrder = queueNumber($chainID);
				$unicommerceCancelJob = (new UnicommerceCancelSaleOrderJob($chainID, $unicommerceArray))->onQueue($queueNumberCancelSaleOrder)->delay(3);
				$this->dispatch($unicommerceCancelJob);
				$order["unicommerceCancelJob"] = $unicommerceCancelJob;
			}
		}

		if ($enableNavisionIntegration == 1) {
			$navSalesReturnArray = array();
			$navSalesReturnArray["orderID"] = $data["orderID"];
			$navSalesReturnArray["storeID"] = $storeID;
			$navSalesReturnArray["refundedOrderID"] = $data['refundOrderID'];
			$navSalesReturnArray['token'] = $request->header('Authorization');
			$navisionSalesReturnJob = (new NavisionNewSalesReturnJob($navSalesReturnArray, $chainID))->onQueue($queueNumber);
			$this->dispatch($navisionSalesReturnJob);
			$order["navJob"] = $navisionSalesReturnJob;

		}

		if ($enableIRDIntegration == 1) {
			$IRDRefundArray = array();
			$IRDRefundArray["order_id"] = $data["orderID"];
			$IRDRefundArray["store_id"] = $storeID;
			$IRDRefundArray["posDate"] = $data['posDate'];
			$IRDRefundArray["refund_order_id"] = $data['refundOrderID'];
			$IRDRefundJob = (new IRDRefundDataJob($IRDRefundArray, $chainID))->onQueue($queueNumber)->delay(6);
			$this->dispatch($IRDRefundJob);
			$order["IRDRefundJob"] = $IRDRefundJob;

		}

		// epos order job dispatch

		$listOfStoresTable = Constants::getGlobalTableName('listOfStores');
		$storeDetail = convertToArray(DB::table($listOfStoresTable)
				->SELECT('pushDataToEpos')
				->where('storeID', $storeID)
				->get());
		if ($storeDetail[0]['pushDataToEpos'] == 1) {
			$queueNumberEPOS = queueNumber($chainID);
			$jobDataArray = array();
			$jobDataArray['storeID'] = $storeID;
			$jobDataArray['orderID'] = $data["orderID"];
			$jobDataArray['refundedOrderID'] = $data['refundOrderID'];
			$jobDataArray['transactionType'] = "ORDER_RETURN";
			$jobEpos = (new SendEPOSOrderJob($jobDataArray, $chainID))->onQueue("$queueNumberEPOS");
			$this->dispatch($jobEpos);
		}

		// end EPOS job dispatch

		// zoho credit note JOB
		if ($enableZohoIntegration == 1) {
			$queueNumberZOHO = queueNumber($chainID);
			$zohoCreditNoteArray = array();
			$zohoCreditNoteArray["orderID"] = $data["orderID"];
			$zohoCreditNoteArray["storeID"] = $storeID;
			$zohoCreditNoteArray['refundedOrderID'] = $data['refundOrderID'];
			$zohoCreditNoteJob = (new ZOHOCreditNoteJob($zohoCreditNoteArray, $chainID))->onQueue($queueNumberZOHO)->delay(3);
			$this->dispatch($zohoCreditNoteJob);
			$order["zohoCreditNoteJob"] = $zohoCreditNoteJob;

		}
		//end zoho invoice JOB

		$enableAccounting = $checkChain[0]["enableAccounting"];

		if ($enableAccounting == 1) {
			$queueNumber = queueNumber($chainID);
			$accRefData = array();
			$accRefData["source"] = "ORDER_CANCEL";
			$accRefData["sourceID"] = $storeID;
			$accRefData["sourceType"] = "STORE";
			$accRefData["transactionID"] = $data["refundOrderID"];
			$accRefData["transactionType"] = "TRN_ORDER_CANCEL";
			$accRefData["orderSummary"] = $orderSummary;
			$accRefData["orderPayment"] = $orderPayment;
			$accountingJob = (new ChainAccountingJob($accRefData, $chainID))->onQueue($queueNumber);
			$this->dispatch($accountingJob);
			$order["accJob"] = $accountingJob;
		}

		/****** mobiquest refund Job ******/

		/****************** Mysquare order update JOB **************/

		$enableMysquareIntegration = $checkChain[0]['enableMysquareIntegration'];
		if ($enableMysquareIntegration == 1) {
			$mySquareOrderArray = array();
			$mySquareOrderArray['orderID'] = $data["orderID"];
			$mySquareOrderArray['chainID'] = $chainID;
			$queueNumberMySquare = queueNumber($chainID);
			$mySquareJob = (new MySquareUpdateOrderJob($mySquareOrderArray, $chainID))->onQueue($queueNumberMySquare);
			$this->dispatch($mySquareJob);
			$order["mySquareJob"] = $mySquareJob;
		}

		/****************** End Mysquare order update JOB **************/

		// check if customerID exist in order

		$orderSummaryTable = Constants::getChainTableName($chainID, "orderSummary");

		$checkCustomer = convertToArray(DB::table($orderSummaryTable)->SELECT("customersIDs")->where('orderID', $data['orderID'])->get());
		if (!empty($checkCustomer)) {
			$customersIDs = $checkCustomer[0]['customersIDs'];
			if ($enableMobiQuestIntegration == 1 && $customersIDs != '') {
				$MqueueNumber = queueNumber($chainID);
				$dataMobiquestArray = array();
				$dataMobiquestArray['orderID'] = $data['orderID'];
				$dataMobiquestArray['storeID'] = $storeID;
				$mobiquestRefundJob = (new mobiquestRefundOrderIntegrationJob($dataMobiquestArray, $chainID))->onQueue($MqueueNumber);
				$this->dispatch($mobiquestRefundJob);
				$order["mobiquestRefundJob"] = $mobiquestRefundJob;
			}
		}

		// if($enableEcomReservation == 1){
		//     $orderID = $data["orderID"];
		//     $orderSummaryTable   = Constants::getChainTableName($chainID,"orderSummary");
		//     $orderSummaryDetails = convertToArray(DB::table($orderSummaryTable)->select('ID','storeID','orderID','Status')->where('orderID', $orderID)->first());
		//     if(isset($orderSummaryDetails["Status"]) && $orderSummaryDetails["Status"] == "ORST_CANCELLED"){
		//         $ecomArray = array();
		//         $ecomArray["storeID"] = $storeID;
		//         $ecomArray["orderID"] = $orderID;
		//         $queueNumberCancelTicket  = queueNumber($chainID);
		//         $ecomCancelTicketJob = (new EcomReservationCancelTicketJob($ecomArray, $chainID))->onQueue($queueNumberCancelTicket)->delay(3);
		//         $this->dispatch($ecomCancelTicketJob);
		//         $order["ecomCancelTicketJob"] = $ecomCancelTicketJob;
		//     }
		// }

		/****** end mobiquest refund Job ******/

		/****** Request Tracker Job ******/
		$data['customerID'] = isset($order['customerID']) ? $order['customerID'] : null;
		$data['requestType'] = 'RETURN';
		$data['storeID'] = $storeID;
		$data['chainID'] = $chainID;

		$ordTrackerJob = (new OrderRequestTrackerJob($data))->onQueue("global");
		$this->dispatch($ordTrackerJob);
		/****** End Request Tracker Job ******/

		//*****   dispatch webhook JOB *******/
		$thirdPartyChainMapTable = Constants::getGlobalTableName("thirdPartyChainMap");
		$getThirdPartyDetail = convertToArray(DB::table($thirdPartyChainMapTable)->SELECT('thirdPartyChainID')->where('chainID', $chainID)->where('status', 'ACTIVE')->where('isActive', 1)->get());
		$globalQBWebhooksTable = Constants::getGlobalTableName("globalQBWebhooks");
		$globalChainWebhookMappingTable = Constants::getGlobalTableName("globalChainWebhookMapping");

		// $getWebhook = convertToArray(DB::table($globalQBWebhooksTable)->select('ID','webhookName')->where('webhookName',"refundInvoice")->get());
		// $webhookID = $getWebhook[0]['ID'];
		// $getWebhookDetail = convertToArray(DB::table($globalChainWebhookMappingTable)->where('webhookID',$webhookID)->where('chainID',$chainID)->where('isWebhookEnabled',1)->get());
		$query = "SELECT * FROM $globalChainWebhookMappingTable WHERE chainID = $chainID AND webhookID = (SELECT ID FROM $globalQBWebhooksTable WHERE webhookName = 'refundInvoice') AND isWebhookEnabled = 1;";
		$getWebhookDetail = convertToArray(DB::select(DB::raw($query)));
		if (!empty($getThirdPartyDetail) && !empty($getWebhookDetail)) {
			$storeDetail = convertToArray(DB::table($listOfStoresTable)->SELECT('managerEmail')->where('storeID', $storeID)->get());
			$thirdPartyChainID = $getThirdPartyDetail[0]['thirdPartyChainID'];
			$queueNumberCustomer = queueNumber($chainID);
			$webhookDataArray = array();
			$webhookDataArray['storeID'] = $storeID;
			$webhookDataArray['chainID'] = $chainID;
			$webhookDataArray['PINumber'] = $data['orderID'];
			$orderDetailArray = array();
			$orderDetailArray['chain_id'] = $chainID;
			$orderDetailArray['store_id'] = $storeID;
			$orderDetailArray['orderID'] = $data['orderID'];
			$orderDetailArray['refundOrderID'] = $data['refundOrderID'];
			$orderDetailArray['third_party_chain_id'] = $thirdPartyChainID;
			$refundOrderdetail = thirdParty::fetchrefundOrderDetail($orderDetailArray, $chainID);
			$refundOrderdetail['data']['managerEmail'] = $storeDetail[0]['managerEmail'];
			$webhookDataArray['webhookType'] = "refundInvoice";
			$webhookDataArray['jsonData'] = $refundOrderdetail['data'];
			$webhookOrderJob = (new customerOrderDetailWebhookJob($webhookDataArray, $chainID))->onQueue("$queueNumberCustomer");
			dispatch($webhookOrderJob);
			$order["webhookOrderJob"] = $webhookOrderJob;
		}

		/********* end webhook JOB  **********/

		if (gettype($order) == "boolean") {
			return response()->json($order, 201, []);
		}

		return response()->json($order, 201, [], JSON_NUMERIC_CHECK);
	} else {
		$sendArray = array();
		$sendArray["HTTPstatus"] = 422;
		$sendArray["storeID"] = $storeID;
		$sendArray["updateOrderJSON"] = $data;
		$sendArray["debugJSON"] = $order;
		$sendArray['orderID'] = $data['orderID'];
		$sendArray['requestHeaders'] = $request->header();
		$sendArray['requestIP'] = $request->ip();
		$sendArray['voidOrderajob'] = isset($jobVoid) ? $jobVoid : null;
		$sendArray['jobVoidEcomPayment'] = isset($jobVoidEcomPayment) ? $jobVoidEcomPayment : null;
		$sendArray['message'] = isset($order["orderUpdationReport"]["message"]) ? $order["orderUpdationReport"]["message"] : "Error in refunding order";
		$order["voidOrderajob"] = isset($jobVoid) ? $jobVoid : null;

		//$temp                         = Restaurants::readRestaurantName($restId);
