    $dataResult = Admin::fetchStockTransferRule($dataArray, $chainID);

    // Send only the requesting user's ID if present in the CSV, else blank
    $headerUserID = $request->header('userid', '');
    if (!empty($headerUserID) && isset($dataResult['data'])) {
        foreach ($dataResult['data'] as &$rule) {
            $userIDs = explode(',', $rule['userID']);
            if (in_array($headerUserID, $userIDs)) {
                $rule['userID'] = $headerUserID;
            } else {
                $rule['userID'] = '';
            }
        }
        unset($rule);
    }

    return response()->json($dataResult, 201, [], JSON_NUMERIC_CHECK);
}

